-- ---------------------
-- TABLE: activation_requests
-- ---------------------
CREATE TABLE IF NOT EXISTS public."activation_requests" (
    "id" integer DEFAULT nextval('activation_requests_id_seq'::regclass) NOT NULL,
    "partner_id" integer,
    "package_id" integer,
    "business_documents" jsonb DEFAULT '{}'::jsonb,
    "notes" text,
    "status" character varying(30) DEFAULT 'pending'::character varying,
    "reviewed_by" integer,
    "reviewed_at" timestamp without time zone,
    "review_notes" text,
    "created_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "updated_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("id")
);

-- ---------------------
-- TABLE: ai_workflow_runs
-- ---------------------
CREATE TABLE IF NOT EXISTS public."ai_workflow_runs" (
    "id" uuid DEFAULT gen_random_uuid() NOT NULL,
    "tenant_id" uuid,
    "workflow_code" character varying(50) NOT NULL,
    "entity_type" character varying(50),
    "entity_id" uuid,
    "input_data" jsonb DEFAULT '{}'::jsonb,
    "output_data" jsonb DEFAULT '{}'::jsonb,
    "status" character varying(20) DEFAULT 'pending'::character varying,
    "error_message" text,
    "tokens_used" integer DEFAULT 0,
    "duration_ms" integer DEFAULT 0,
    "created_by" integer,
    "created_at" timestamp with time zone DEFAULT now(),
    "updated_at" timestamp with time zone DEFAULT now(),
    PRIMARY KEY ("id")
);

-- ---------------------
-- TABLE: announcements
-- ---------------------
CREATE TABLE IF NOT EXISTS public."announcements" (
    "id" uuid DEFAULT uuid_generate_v4() NOT NULL,
    "tenant_id" uuid,
    "title" character varying(255) NOT NULL,
    "content" text NOT NULL,
    "category" character varying(30) DEFAULT 'general'::character varying,
    "priority" character varying(20) DEFAULT 'normal'::character varying,
    "status" character varying(20) DEFAULT 'draft'::character varying,
    "author_id" uuid,
    "author_name" character varying(150),
    "target_departments" jsonb DEFAULT '[]'::jsonb,
    "target_branches" jsonb DEFAULT '[]'::jsonb,
    "published_at" timestamp with time zone,
    "expires_at" timestamp with time zone,
    "is_pinned" boolean DEFAULT false,
    "attachments" jsonb DEFAULT '[]'::jsonb,
    "read_count" integer DEFAULT 0,
    "read_by" jsonb DEFAULT '[]'::jsonb,
    "created_at" timestamp with time zone DEFAULT now(),
    "updated_at" timestamp with time zone DEFAULT now(),
    PRIMARY KEY ("id")
);

-- ---------------------
