-- ---------------------
-- TABLE: branches
-- ---------------------
CREATE TABLE IF NOT EXISTS public."branches" (
    "id" uuid DEFAULT gen_random_uuid() NOT NULL,
    "tenant_id" uuid,
    "store_id" uuid,
    "code" character varying(50) NOT NULL,
    "name" character varying(255) NOT NULL,
    "type" character varying(20) DEFAULT 'branch'::character varying,
    "address" text,
    "city" character varying(255),
    "province" character varying(255),
    "postal_code" character varying(10),
    "phone" character varying(20),
    "email" character varying(255),
    "manager_id" integer,
    "operating_hours" jsonb DEFAULT '[]'::jsonb,
    "is_active" boolean DEFAULT true,
    "settings" jsonb DEFAULT '{}'::jsonb,
    "created_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "updated_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "region" character varying(100),
    "last_sync_at" timestamp without time zone,
    "sync_status" character varying(20) DEFAULT 'never'::character varying,
    PRIMARY KEY ("id"),
    CONSTRAINT "branches_code_key" UNIQUE ("code"),
    CONSTRAINT "branches_type_check" CHECK (((type)::text = ANY ((ARRAY['main'::character varying, 'branch'::character varying, 'warehouse'::character varying, 'kiosk'::character varying])::text[])))
);

