    "transfer_id" integer NOT NULL,
    "product_id" integer NOT NULL,
    "product_name" character varying(255) NOT NULL,
    "product_sku" character varying(100),
    "quantity_requested" numeric(10,2) NOT NULL,
    "quantity_approved" numeric(10,2),
    "quantity_shipped" numeric(10,2),
    "quantity_received" numeric(10,2),
    "condition_on_receipt" character varying(50),
    "unit_cost" numeric(15,2) NOT NULL,
    "subtotal" numeric(15,2) NOT NULL,
    "notes" text,
    "created_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "updated_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("id"),
    CONSTRAINT "chk_positive_quantity" CHECK ((quantity_requested > (0)::numeric)),
    CONSTRAINT "chk_valid_condition" CHECK (((condition_on_receipt)::text = ANY ((ARRAY['good'::character varying, 'damaged'::character varying, 'missing'::character varying, 'partial'::character varying, NULL::character varying])::text[])))
);

