    "reason" text NOT NULL,
    "status" character varying(30) DEFAULT 'requested'::character varying NOT NULL,
    "approved_by" character varying(100),
    "approval_date" timestamp without time zone,
    "approval_notes" text,
    "shipment_date" timestamp without time zone,
    "tracking_number" character varying(100),
    "courier" character varying(100),
    "estimated_arrival" date,
    "shipped_by" character varying(100),
    "received_date" timestamp without time zone,
    "received_by" character varying(100),
    "receipt_notes" text,
    "total_cost" numeric(15,2) DEFAULT 0 NOT NULL,
    "shipping_cost" numeric(15,2) DEFAULT 0 NOT NULL,
    "handling_fee" numeric(15,2) DEFAULT 0 NOT NULL,
    "notes" text,
    "attachments" json,
    "requested_by" character varying(100) NOT NULL,
    "created_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "updated_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("id"),
    CONSTRAINT "inventory_transfers_transfer_number_key" UNIQUE ("transfer_number"),
    CONSTRAINT "chk_different_locations" CHECK ((from_location_id <> to_location_id)),
    CONSTRAINT "chk_valid_priority" CHECK (((priority)::text = ANY ((ARRAY['normal'::character varying, 'urgent'::character varying, 'emergency'::character varying])::text[]))),
    CONSTRAINT "chk_valid_status" CHECK (((status)::text = ANY ((ARRAY['requested'::character varying, 'approved'::character varying, 'rejected'::character varying, 'in_preparation'::character varying, 'in_transit'::character varying, 'received'::character varying, 'completed'::character varying, 'cancelled'::character varying])::text[])))
);

