CREATE TABLE IF NOT EXISTS public."kitchen_order_items" (
    "id" uuid NOT NULL,
    "kitchen_order_id" uuid NOT NULL,
    "product_id" uuid NOT NULL,
    "recipe_id" uuid,
    "name" character varying(255) NOT NULL,
    "quantity" integer DEFAULT 1 NOT NULL,
    "notes" text,
    "modifiers" json,
    "status" public.enum_kitchen_order_items_status DEFAULT 'pending'::enum_kitchen_order_items_status NOT NULL,
    "prepared_by" uuid,
    "created_at" timestamp with time zone NOT NULL,
    "updated_at" timestamp with time zone NOT NULL,
    PRIMARY KEY ("id")
);

-- ---------------------
-- TABLE: kitchen_orders
-- ---------------------
CREATE TABLE IF NOT EXISTS public."kitchen_orders" (
    "id" uuid NOT NULL,
    "tenant_id" uuid NOT NULL,
    "order_number" character varying(255) NOT NULL,
    "pos_transaction_id" uuid,
    "table_number" character varying(255),
    "order_type" public.enum_kitchen_orders_order_type DEFAULT 'dine-in'::enum_kitchen_orders_order_type NOT NULL,
    "customer_name" character varying(255),
    "status" public.enum_kitchen_orders_status DEFAULT 'new'::enum_kitchen_orders_status NOT NULL,
    "priority" public.enum_kitchen_orders_priority DEFAULT 'normal'::enum_kitchen_orders_priority NOT NULL,
    "received_at" timestamp with time zone NOT NULL,
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "served_at" timestamp with time zone,
    "estimated_time" integer,
    "actual_prep_time" integer,
    "assigned_chef_id" uuid,
    "notes" text,
