    "created_at" timestamp with time zone NOT NULL,
    "updated_at" timestamp with time zone NOT NULL,
    PRIMARY KEY ("id"),
    CONSTRAINT "kitchen_orders_order_number_key" UNIQUE ("order_number")
);

-- ---------------------
-- TABLE: kitchen_recipe_ingredients
