-- ---------------------
-- TABLE: kitchen_schedules
-- ---------------------
CREATE TABLE IF NOT EXISTS public."kitchen_schedules" (
    "id" uuid DEFAULT gen_random_uuid() NOT NULL,
    "staff_id" uuid NOT NULL,
    "date" date NOT NULL,
    "shift" character varying(10) NOT NULL,
    "status" character varying(15) DEFAULT 'scheduled'::character varying NOT NULL,
    "notes" text,
    "created_at" timestamp with time zone DEFAULT now(),
    "updated_at" timestamp with time zone DEFAULT now(),
    PRIMARY KEY ("id"),
    CONSTRAINT "unique_staff_date" UNIQUE ("staff_id", "date"),
    CONSTRAINT "kitchen_schedules_shift_check" CHECK (((shift)::text = ANY ((ARRAY['morning'::character varying, 'afternoon'::character varying, 'night'::character varying, 'off'::character varying])::text[]))),
    CONSTRAINT "kitchen_schedules_status_check" CHECK (((status)::text = ANY ((ARRAY['scheduled'::character varying, 'confirmed'::character varying, 'completed'::character varying, 'absent'::character varying, 'leave'::character varying])::text[])))
);

-- ---------------------
-- TABLE: kitchen_staff
-- ---------------------
CREATE TABLE IF NOT EXISTS public."kitchen_staff" (
    "id" uuid DEFAULT gen_random_uuid() NOT NULL,
    "tenant_id" uuid NOT NULL,
    "user_id" uuid,
    "name" character varying(255) NOT NULL,
    "role" character varying(20) DEFAULT 'line_cook'::character varying NOT NULL,
    "shift" character varying(10) DEFAULT 'morning'::character varying NOT NULL,
    "status" character varying(10) DEFAULT 'active'::character varying NOT NULL,
    "performance" numeric(5,2) DEFAULT 0,
    "orders_completed" integer DEFAULT 0,
    "avg_prep_time" integer,
    "join_date" timestamp with time zone DEFAULT now(),
    "phone" character varying(20),
    "email" character varying(255),
    "is_active" boolean DEFAULT true,
    "created_at" timestamp with time zone DEFAULT now(),
    "updated_at" timestamp with time zone DEFAULT now(),
    PRIMARY KEY ("id"),
    CONSTRAINT "kitchen_staff_role_check" CHECK (((role)::text = ANY ((ARRAY['head_chef'::character varying, 'sous_chef'::character varying, 'line_cook'::character varying, 'prep_cook'::character varying])::text[]))),
    CONSTRAINT "kitchen_staff_shift_check" CHECK (((shift)::text = ANY ((ARRAY['morning'::character varying, 'afternoon'::character varying, 'night'::character varying])::text[]))),
    CONSTRAINT "kitchen_staff_status_check" CHECK (((status)::text = ANY ((ARRAY['active'::character varying, 'off'::character varying, 'leave'::character varying])::text[])))
);

