    "updated_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("id"),
    CONSTRAINT "chk_business_structure" CHECK (((business_structure)::text = ANY ((ARRAY['single'::character varying, 'multi_branch'::character varying])::text[]))),
    CONSTRAINT "chk_kyb_status" CHECK (((status)::text = ANY ((ARRAY['draft'::character varying, 'submitted'::character varying, 'in_review'::character varying, 'approved'::character varying, 'rejected'::character varying, 'revision_needed'::character varying])::text[]))),
    CONSTRAINT "chk_legal_entity" CHECK (((legal_entity_type)::text = ANY ((ARRAY['pt'::character varying, 'cv'::character varying, 'ud'::character varying, 'perorangan'::character varying, 'koperasi'::character varying, 'yayasan'::character varying, NULL::character varying])::text[])))
);

