-- ---------------------
-- TABLE: recipes
-- ---------------------
CREATE TABLE IF NOT EXISTS public."recipes" (
    "id" integer DEFAULT nextval('recipes_id_seq'::regclass) NOT NULL,
    "code" character varying(50) NOT NULL,
    "name" character varying(255) NOT NULL,
    "description" text,
    "product_id" integer,
    "batch_size" numeric(10,2) DEFAULT 1 NOT NULL,
    "batch_unit" character varying(20) DEFAULT 'pcs'::character varying NOT NULL,
    "estimated_yield" numeric(10,2),
    "yield_percentage" numeric(5,2) DEFAULT 100,
    "preparation_time_minutes" integer DEFAULT 0,
    "cooking_time_minutes" integer DEFAULT 0,
    "total_time_minutes" integer DEFAULT 0,
    "total_cost" numeric(15,2) DEFAULT 0,
    "labor_cost" numeric(15,2) DEFAULT 0,
    "overhead_cost" numeric(15,2) DEFAULT 0,
    "total_production_cost" numeric(15,2) DEFAULT 0,
    "cost_per_unit" numeric(15,2) DEFAULT 0,
    "difficulty_level" character varying(10) DEFAULT 'medium'::character varying,
    "category" character varying(100),
    "status" character varying(10) DEFAULT 'draft'::character varying,
    "version" integer DEFAULT 1,
    "instructions" text,
    "notes" text,
    "created_by" integer,
    "created_at" timestamp with time zone DEFAULT now(),
    "updated_at" timestamp with time zone DEFAULT now(),
    PRIMARY KEY ("id"),
    CONSTRAINT "recipes_code_key" UNIQUE ("code"),
    CONSTRAINT "recipes_difficulty_level_check" CHECK (((difficulty_level)::text = ANY ((ARRAY['easy'::character varying, 'medium'::character varying, 'hard'::character varying])::text[]))),
    CONSTRAINT "recipes_status_check" CHECK (((status)::text = ANY ((ARRAY['draft'::character varying, 'active'::character varying, 'archived'::character varying])::text[])))
);

