CREATE TABLE IF NOT EXISTS public."sfa_survey_responses" (
    "id" uuid DEFAULT gen_random_uuid() NOT NULL,
    "tenant_id" uuid,
    "template_id" uuid,
    "visit_id" uuid,
    "customer_id" uuid,
    "customer_name" character varying(200),
    "respondent_id" integer,
    "response_date" date DEFAULT CURRENT_DATE,
    "answers" jsonb DEFAULT '{}'::jsonb,
    "score" numeric(5,2),
    "completion_pct" numeric(5,2) DEFAULT 100,
    "duration_seconds" integer,
    "status" character varying(20) DEFAULT 'completed'::character varying,
    "lat" numeric(10,7),
    "lng" numeric(10,7),
    "notes" text,
    "created_at" timestamp with time zone DEFAULT now(),
    PRIMARY KEY ("id")
);

-- ---------------------
-- TABLE: sfa_survey_templates
-- ---------------------
CREATE TABLE IF NOT EXISTS public."sfa_survey_templates" (
    "id" uuid DEFAULT gen_random_uuid() NOT NULL,
    "tenant_id" uuid,
    "code" character varying(30) NOT NULL,
    "title" character varying(200) NOT NULL,
    "description" text,
    "survey_type" character varying(30) DEFAULT 'general'::character varying,
    "target_audience" character varying(30) DEFAULT 'customer'::character varying,
    "is_required" boolean DEFAULT false,
    "trigger_event" character varying(30),
    "question_count" integer DEFAULT 0,
    "estimated_minutes" integer DEFAULT 5,
    "status" character varying(20) DEFAULT 'active'::character varying,
    "valid_from" date,
    "valid_to" date,
    "metadata" jsonb DEFAULT '{}'::jsonb,
    "created_by" integer,
    "updated_by" integer,
    "created_at" timestamp with time zone DEFAULT now(),
    "updated_at" timestamp with time zone DEFAULT now(),
    PRIMARY KEY ("id"),
    CONSTRAINT "sfa_st_uq" UNIQUE ("tenant_id", "code")
);

-- ---------------------
